}

// Per-insn tick for BBV-emit mode. udata is the bb_id (1-based) cast to
// pointer; that mapping is stable across calls because bbv_emit_assign_id
// is hashed by TB-start PC. The tick attributes one insn to the bb_id and
// flushes a slice row when the per-slice counter saturates.
static void on_bbv_tick(unsigned int vcpu_idx, void *udata)
{
    (void) vcpu_idx;
    uint64_t bb_id = (uint64_t) GPOINTER_TO_UINT(udata);
    bbv_emit_tick(bbv_emit, bb_id);
}

// Per-insn tick for slice-consume mode (F11). Counts insns into the
// slice accumulator; on each slice boundary increments slice_consume_idx
// and resets the accumulator. Once slice_consume_idx exceeds the target
// slice index, drains via on_handoff at that same insn boundary. udata
// is the per-insn HandoffSite (allocated at translation time) so the
// post-trigger PC reaches on_handoff lag-free.
static void on_slice_consume_tick(unsigned int vcpu_idx, void *udata)
{
    if (++slice_consume_acc < bbv_slice_target) return;
    slice_consume_acc = 0;
    if (slice_consume_idx++ < slice_at_target) return;
    // After the post-increment above, slice_consume_idx == slice_at_target+1
    // (the count of fully retired slices). Log so the e2e test can verify
    // drain timing without relying on minstret (which is a cycle-counter
    // proxy on andes-ax45mpv and does not track plugin-counted insns).
    fprintf(stderr,
            "hybrid_handoff: slice-consume drain (idx=%" PRIu64
            " target=%" PRIu64 ")\n",
            slice_consume_idx, slice_at_target);
    on_handoff(vcpu_idx, udata);
}

static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
{
