        uint64_t tb_pc = qemu_plugin_insn_vaddr(qemu_plugin_tb_get_insn(tb, 0));
        bb_id = bbv_emit_assign_id(bbv_emit, tb_pc);
    }

    for (size_t i = 0; i < n; i++) {
        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);

        // F14 count tick: registered FIRST so the count is incremented
        // before any trigger callback can call exit(200). NO_REGS keeps
        // the per-insn cost minimal (a single uint64 add).
        if (drain_at_exit_mode) {
