auto check_hybrid_handoff() -> std::optional<int>
{
  if constexpr (!requires { cpu.get_committed_pc(); }) {
    return std::nullopt;
  } else {
    const auto committed = cpu.get_committed_pc();
    if (committed.empty()) return std::nullopt;
    auto gpr_probe = [&](uint8_t r) -> uint64_t {
      if constexpr (requires { cpu.get_gpr(r); }) {
        return cpu.get_gpr(r);
      }
      return 0;
    };
    for (const auto pc: committed[0]) {
      auto state = std::optional<hybrid_state_v1>{};
      if (hybrid_handoff_)
        state = hybrid_handoff_->on_retire(pc, gpr_probe);
      else if (hybrid_icount_handoff_)
        state = hybrid_icount_handoff_->on_retire(pc, gpr_probe);
      if (state) {
        // V-register merge: the fixture's vsim-phase epilogue is expected
        // to have run vse8.v v0..v31 to scratch RAM before the exit
        // trigger fired. Read those bytes back into state.vreg[] so the
        // gdbstub-driven QEMU 2 restore sees vsim's actual values, not
        // QEMU 1's stale snapshot.
        if ((state->flags & HYBRID_FLAG_V) != 0u) {
          hybrid::read_v_from_scratch(
            *state,
            std::span<const uint8_t>{platform.main_memory.data.data(),
                                     platform.main_memory.data.size()},
            platform.main_memory.region.base_address);
        }
        spdlog::info("hybrid handoff: drained at pc=0x{:x}, writing {}",
                     pc, hybrid_state_path_);
        std::ofstream f(hybrid_state_path_, std::ios::binary);
        f.write(reinterpret_cast<const char*>(&*state), sizeof(*state));
        return hybrid::kExitHandoffToQemu;
      }
    }
    return std::nullopt;
  }
}

void enable_waveform(const std::string& waveform_filename)
{
  trace_.enable_waveform(cpu, waveform_filename);
}

void enable_pc_trace(const std::string& filename)
{
  trace_.enable_pc_trace(filename);
}

void disable_pc_trace() { trace_.disable_pc_trace(); }

// IcountTrigger - F6 sibling of CsrTrigger. Counts retired insns and fires
// HYBRID_HANDOFF_EXIT once the per-hart counter reaches the configured target.
// Pure logic: no SystemC, no DMI bus.
//
// Duck-types the CsrTrigger surface so HandoffController's template
// instantiates cleanly for either:
//
//   - lookup(pc) -> std::optional<CsrTriggerHit>
//   - empty() -> bool
//   - observe_commit() -> void  (icount-specific; HandoffController calls
//                                via if-constexpr requires-clause)
//
// `pc` is ignored: icount fires on counter alone, not at any specific PC.
// Multi-hart out of scope - the counter is a single uint64_t, sized for one
// hart per plan-validation contract.

#pragma once

#include "hybrid/csr_trigger.hpp"
#include "hybrid/insn_match.h"

#include <cstdint>
#include <optional>

namespace hybrid
{

class IcountTrigger
{
public:
  explicit IcountTrigger(uint64_t target) : target_{target} {}

  void observe_commit() noexcept { ++retired_; }

  auto lookup(uint64_t /*pc*/) const -> std::optional<CsrTriggerHit>
  {
    if (target_ == 0 || retired_ < target_) return std::nullopt;
    return CsrTriggerHit{HYBRID_HANDOFF_EXIT, /*insn=*/0u};
  }

  auto empty() const -> bool { return target_ == 0; }

  auto target() const -> uint64_t { return target_; }
  auto retired() const -> uint64_t { return retired_; }

private:
  uint64_t target_;
  uint64_t retired_ = 0;
};

}  // namespace hybrid

