static void vcpu_tb_trans(qemu_plugin_id_t id, struct qemu_plugin_tb *tb)
{
    (void) id;
    size_t n = qemu_plugin_tb_n_insns(tb);

    // BBV-mode: assign a stable bb_id to this TB (1-based, hashed by
    // TB-start vaddr). Same id is shared by every insn in the TB.
    uint64_t bb_id = 0;
    if (bbv_mode && n > 0) {
        uint64_t tb_pc = qemu_plugin_insn_vaddr(qemu_plugin_tb_get_insn(tb, 0));
        bb_id = bbv_emit_assign_id(bbv_emit, tb_pc);
    }

    for (size_t i = 0; i < n; i++) {
        struct qemu_plugin_insn *insn = qemu_plugin_tb_get_insn(tb, i);

        // F14 count tick: registered FIRST so the count is incremented
        // before any trigger callback can call exit(200). NO_REGS keeps
        // the per-insn cost minimal (a single uint64 add).
        if (drain_at_exit_mode) {
            qemu_plugin_register_vcpu_insn_exec_cb(
                insn, on_count_tick, QEMU_PLUGIN_CB_NO_REGS, NULL);
        }

        // BBV callback is registered BEFORE icount so that if both modes
        // fire on the same insn (icount target == slice multiple), the
        // slice row is emitted before exit(200) is called.
        if (bbv_mode) {
            qemu_plugin_register_vcpu_insn_exec_cb(
                insn, on_bbv_tick, QEMU_PLUGIN_CB_NO_REGS,
                GUINT_TO_POINTER((guint) bb_id));
        }

        // Slice-consume callback (F11). Registered after BBV so a BBV
        // row at the same boundary is flushed first; ordering vs icount
        // is irrelevant (both drain).
        if (slice_consume_mode) {
            HandoffSite *site = g_new0(HandoffSite, 1);
            site->kind  = HYBRID_HANDOFF_ENTER;
            site->vaddr = qemu_plugin_insn_vaddr(insn);
            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
            qemu_plugin_register_vcpu_insn_exec_cb(
                insn, on_slice_consume_tick, QEMU_PLUGIN_CB_R_REGS, site);
        }

        if (icount_mode) {
            HandoffSite *site = g_new0(HandoffSite, 1);
            site->kind  = HYBRID_HANDOFF_ENTER;
            site->vaddr = qemu_plugin_insn_vaddr(insn);
            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
            qemu_plugin_register_vcpu_insn_exec_cb(
                insn, on_icount_tick, QEMU_PLUGIN_CB_R_REGS, site);
        }

        if (pc_mode) {
            // PC-trigger mode: vaddr-only match. qemu_plugin_insn_size lets
            // a future fixture park enter_pc on a compressed insn -- next-PC
            // is computed from the API-reported size, not assumed to be 4.
            if (qemu_plugin_insn_vaddr(insn) != enter_pc_arg) continue;
            HandoffSite *site = g_new0(HandoffSite, 1);
            site->kind  = HYBRID_HANDOFF_ENTER;
            site->vaddr = qemu_plugin_insn_vaddr(insn);
            site->size  = (uint32_t) qemu_plugin_insn_size(insn);
            qemu_plugin_register_vcpu_insn_exec_cb(
                insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
            continue;
        }

        // CSR-trigger mode (default).
        size_t sz = qemu_plugin_insn_size(insn);
        if (sz != 4) continue;
        uint32_t raw = 0;
        if (qemu_plugin_insn_data(insn, &raw, sizeof(raw)) != sizeof(raw))
            continue;
        hybrid_handoff_kind kind = HYBRID_HANDOFF_NONE;
        if (!hybrid_match_handoff_insn(raw, &kind)) continue;
        HandoffSite *site = g_new0(HandoffSite, 1);
        site->kind  = kind;
        site->vaddr = qemu_plugin_insn_vaddr(insn);
        site->size  = (uint32_t) sz;
        qemu_plugin_register_vcpu_insn_exec_cb(
            insn, on_handoff, QEMU_PLUGIN_CB_R_REGS, site);
    }
}

